//! `d1` -- command-line driver for DiscoveryOne.
//!
//! Subcommand surface defined in `docs/design.md` section 9.
//! In the M0 scaffold (`discoveryone-scaffold`) every
//! subcommand is a stub: it parses arguments, prints
//! `not yet implemented` to stderr, and exits 1. Only
//! `--help` and `--version` produce stable output, which the
//! `d1_smoke_cli_help` reg-rs baseline locks in.

use std::path::PathBuf;
use std::process::ExitCode;

use clap::{Parser, Subcommand};

const ABOUT: &str =
    "DiscoveryOne language driver. Test-harness CLI; see docs/design.md.";

#[derive(Parser)]
#[command(
    name = "d1",
    version,
    about = ABOUT,
    long_about = None,
    disable_help_subcommand = true
)]
struct Cli {
    #[command(subcommand)]
    cmd: Cmd,
}

#[derive(Subcommand)]
enum Cmd {
    /// Dump the token stream for FILE (one token per line).
    Lex {
        /// Source file (.d1 or .d1.json).
        file: PathBuf,
    },
    /// Dump the AST for FILE as a deterministic s-expression.
    Parse {
        /// Source file.
        file: PathBuf,
    },
    /// Project FILE onto FACE; print the 2D token grid.
    Face {
        /// Source file.
        file: PathBuf,
        /// Face name: front, left, right, top, bottom, rear.
        #[arg(long)]
        face: String,
    },
    /// Run the facet checker over FILE.
    Check {
        /// Source file.
        file: PathBuf,
    },
    /// Print the stack IR for FILE.
    Lower {
        /// Source file.
        file: PathBuf,
    },
    /// Emit FILE as a .wasm module.
    EmitWasm {
        /// Source file.
        file: PathBuf,
        /// Output path for the .wasm bytes.
        #[arg(short = 'o', long = "out")]
        out: PathBuf,
    },
    /// Execute FILE via the WASM runtime (wasmtime).
    Run {
        /// Source file.
        file: PathBuf,
        /// Inputs as KEY=VALUE pairs (comma-separated or repeated).
        #[arg(long, value_delimiter = ',')]
        inputs: Vec<String>,
    },
    /// Execute FILE via the reference interpreter.
    Interp {
        /// Source file.
        file: PathBuf,
        /// Inputs as KEY=VALUE pairs (comma-separated or repeated).
        #[arg(long, value_delimiter = ',')]
        inputs: Vec<String>,
    },
    /// Round-trip FILE between layered text and JSON.
    Normalize {
        /// Source file.
        file: PathBuf,
    },
    /// Render FACE of FILE as deterministic ASCII (for reg-rs).
    FacetSnapshot {
        /// Source file.
        file: PathBuf,
        /// Face name: front, left, right, top, bottom, rear.
        #[arg(long)]
        face: String,
    },
}

impl Cmd {
    fn name(&self) -> &'static str {
        match self {
            Cmd::Lex { .. } => "lex",
            Cmd::Parse { .. } => "parse",
            Cmd::Face { .. } => "face",
            Cmd::Check { .. } => "check",
            Cmd::Lower { .. } => "lower",
            Cmd::EmitWasm { .. } => "emit-wasm",
            Cmd::Run { .. } => "run",
            Cmd::Interp { .. } => "interp",
            Cmd::Normalize { .. } => "normalize",
            Cmd::FacetSnapshot { .. } => "facet-snapshot",
        }
    }
}

fn main() -> ExitCode {
    let cli = Cli::parse();
    eprintln!("d1 {}: not yet implemented", cli.cmd.name());
    ExitCode::from(1)
}

